9: /// <summary>
10: /// Displays a list of validation messages for a specified field within a cascaded <see cref="EditContext"/>.
11: /// </summary>
12: public class ValidationMessage<TValue> : ComponentBase, IDisposable
13: {
14:     private EditContext? _previousEditContext;
15:     private Expression<Func<TValue>>? _previousFieldAccessor;
16:     private readonly EventHandler<ValidationStateChangedEventArgs>? _validationStateChangedHandler;
17:     private FieldIdentifier _fieldIdentifier;
18: 
19:     /// <summary>
20:     /// Gets or sets a collection of additional attributes that will be applied to the created <c>div</c> element.
21:     /// </summary>
22:     [Parameter(CaptureUnmatchedValues = true)] public IReadOnlyDictionary<string, object>? AdditionalAttributes { get; set; }
23: 
24:     [CascadingParameter] EditContext CurrentEditContext { get; set; } = default!;
25: 
26:     /// <summary>
27:     /// Specifies the field for which validation messages should be displayed.
28:     /// </summary>
29:     [Parameter] public Expression<Func<TValue>>? For { get; set; }
30: 
31:     /// <summary>`
32:     /// Constructs an instance of <see cref="ValidationMessage{TValue}"/>.
33:     /// </summary>
34:     public ValidationMessage()
35:     {
36:         _validationStateChangedHandler = (sender, eventArgs) => StateHasChanged();
37:     }
38: 
39:     /// <inheritdoc />
40:     protected override void OnParametersSet()
41:     {
42:         if (CurrentEditContext == null)
43:         {
44:             throw new InvalidOperationException($"{GetType()} requires a cascading parameter " +
45:                 $"of type {nameof(EditContext)}. For example, you can use {GetType()} inside " +
46:                 $"an {nameof(EditForm)}.");
47:         }
48: 
49:         if (For == null) // Not possible except if you manually specify T
50:         {
51:             throw new InvalidOperationException($"{GetType()} requires a value for the " +
52:                 $"{nameof(For)} parameter.");
53:         }
54:         else if (For != _previousFieldAccessor)
55:         {            
56:             _fieldIdentifier = FieldIdentifier.Create(For);
57:             _previousFieldAccessor = For;
58:         }
59: 
60:         if (CurrentEditContext != _previousEditContext)
61:         {
62:             DetachValidationStateChangedListener();
63:             CurrentEditContext.OnValidationStateChanged += _validationStateChangedHandler;
64:             _previousEditContext = CurrentEditContext;
65:         }
66:     }
67: 
68:     /// <inheritdoc />
69:     protected override void BuildRenderTree(RenderTreeBuilder builder)
70:     {
71:         foreach (var message in CurrentEditContext.GetValidationMessages(_fieldIdentifier))
72:         {
73:             builder.OpenElement(0, "div");
74:             builder.AddAttribute(1, "class", "validation-message");
75:             builder.AddMultipleAttributes(2, AdditionalAttributes);
76:             builder.AddContent(3, message);
77:             builder.CloseElement();
78:         }
79:     }
80: 
81:     /// <summary>
82:     /// Called to dispose this instance.
83:     /// </summary>
84:     /// <param name="disposing"><see langword="true"/> if called within <see cref="IDisposable.Dispose"/>.</param>
85:     protected virtual void Dispose(bool disposing)
86:     {
87:     }
88: 
89:     void IDisposable.Dispose()
90:     {
91:         DetachValidationStateChangedListener();
92:         Dispose(disposing: true);
93:     }
94: 
95:     private void DetachValidationStateChangedListener()
96:     {
97:         if (_previousEditContext != null)
98:         {
99:             _previousEditContext.OnValidationStateChanged -= _validationStateChangedHandler;
100:         }
101:     }
102: }
