37:     {
38:         _validationStateChangedHandler = (sender, eventArgs) => StateHasChanged();
39:     }
40: 
41:     /// <inheritdoc />
42:     protected override void OnParametersSet()
43:     {
44:         if (CurrentEditContext == null)
45:         {
46:             throw new InvalidOperationException($"{nameof(ValidationSummary)} requires a cascading parameter " +
47:                 $"of type {nameof(EditContext)}. For example, you can use {nameof(ValidationSummary)} inside " +
48:                 $"an {nameof(EditForm)}.");
49:         }
50: 
51:         if (CurrentEditContext != _previousEditContext)
52:         {
53:             DetachValidationStateChangedListener();
