25:     public static readonly RouteTableFactory Instance = new();
26:     public static readonly IComparer<InboundRouteEntry> RouteOrder = Comparer<InboundRouteEntry>.Create((x, y) =>
27:     {
28:         var result = RouteComparison(x, y);
29:         return result != 0 ? result : string.Compare(x.RoutePattern.RawText, y.RoutePattern.RawText, StringComparison.OrdinalIgnoreCase);
30:     });
