32:     private readonly ConcurrentDictionary<RouteKey, RouteTable> _cache = new();
33: 
34:     public RouteTable Create(RouteKey routeKey, IServiceProvider serviceProvider)
35:     {
36:         if (_cache.TryGetValue(routeKey, out var resolvedComponents))
37:         {
38:             return resolvedComponents;
39:         }
40: 
41:         var componentTypes = GetRouteableComponents(routeKey);
42:         var routeTable = Create(componentTypes, serviceProvider);
43:         _cache.TryAdd(routeKey, routeTable);
44:         return routeTable;
45:     }
46: 
47:     public void ClearCaches() => _cache.Clear();
