49:     [UnconditionalSuppressMessage("Trimming", "IL2026", Justification = "Application code does not get trimmed, and the framework does not define routable components.")]
50:     private static List<Type> GetRouteableComponents(RouteKey routeKey)
51:     {
52:         var routeableComponents = new List<Type>();
53:         if (routeKey.AppAssembly is not null)
54:         {
55:             GetRouteableComponents(routeableComponents, routeKey.AppAssembly);
56:         }
57: 
58:         if (routeKey.AdditionalAssemblies is not null)
59:         {
60:             foreach (var assembly in routeKey.AdditionalAssemblies)
61:             {
62:                 // We don't need process the assembly if it's the app assembly.
63:                 if (assembly != routeKey.AppAssembly)
64:                 {
65:                     GetRouteableComponents(routeableComponents, assembly);
66:                 }
67:             }
68:         }
69: 
70:         return routeableComponents;
