73:         {
74:             foreach (var type in assembly.ExportedTypes)
75:             {
76:                 if (typeof(IComponent).IsAssignableFrom(type)
77:                     && type.IsDefined(typeof(RouteAttribute))
78:                     && !type.IsDefined(typeof(ExcludeFromInteractiveRoutingAttribute)))
79:                 {
80:                     routeableComponents.Add(type);
