4: using System.Collections.Concurrent;
5: using System.Diagnostics.CodeAnalysis;
6: using System.Linq.Expressions;
7: using System.Reflection;
8: using System.Runtime.CompilerServices;
9: using Microsoft.AspNetCore.Components.HotReload;
10: 
11: namespace Microsoft.AspNetCore.Components.Forms;
12: 
13: /// <summary>
14: /// Uniquely identifies a single field that can be edited. This may correspond to a property on a
15: /// model object, or can be any other named value.
16: /// </summary>
17: public readonly struct FieldIdentifier : IEquatable<FieldIdentifier>
18: {
19:     private static readonly ConcurrentDictionary<(Type ModelType, MemberInfo Member), Func<object, object>> _fieldAccessors = new();
20: 
21:     static FieldIdentifier()
22:     {
23:         if (HotReloadManager.Default.MetadataUpdateSupported)
24:         {
25:             HotReloadManager.Default.OnDeltaApplied += ClearCache;
26:         }
27:     }
28: 
29:     /// <summary>
30:     /// Initializes a new instance of the <see cref="FieldIdentifier"/> structure.
31:     /// </summary>
32:     /// <param name="accessor">An expression that identifies an object member.</param>
33:     /// <typeparam name="TField">The field <see cref="Type"/>.</typeparam>
34:     public static FieldIdentifier Create<TField>(Expression<Func<TField>> accessor)
35:     {
36:         ArgumentNullException.ThrowIfNull(accessor);
37: 
38:         ParseAccessor(accessor, out var model, out var fieldName);
39:         return new FieldIdentifier(model, fieldName);
40:     }
41: 
42:     /// <summary>
43:     /// Initializes a new instance of the <see cref="FieldIdentifier"/> structure.
44:     /// </summary>
45:     /// <param name="model">The object that owns the field.</param>
46:     /// <param name="fieldName">The name of the editable field.</param>
47:     public FieldIdentifier(object model, string fieldName)
48:     {
49:         ArgumentNullException.ThrowIfNull(model);
50: 
51:         if (model.GetType().IsValueType)
52:         {
53:             throw new ArgumentException("The model must be a reference-typed object.", nameof(model));
54:         }
55: 
56:         Model = model;
57: 
58:         // Note that we do allow an empty string. This is used by some validation systems
59:         // as a place to store object-level (not per-property) messages.
60:         FieldName = fieldName ?? throw new ArgumentNullException(nameof(fieldName));
61:     }
62: 
63:     /// <summary>
64:     /// Gets the object that owns the editable field.
65:     /// </summary>
66:     public object Model { get; }
67: 
68:     /// <summary>
69:     /// Gets the name of the editable field.
70:     /// </summary>
71:     public string FieldName { get; }
72: 
73:     /// <inheritdoc />
74:     public override int GetHashCode()
75:     {
76:         // We want to compare Model instances by reference. RuntimeHelpers.GetHashCode returns identical hashes for equal object references (ignoring any `Equals`/`GetHashCode` overrides) which is what we want.
77:         var modelHash = RuntimeHelpers.GetHashCode(Model);
78:         var fieldHash = StringComparer.Ordinal.GetHashCode(FieldName);
79:         return (
80:             modelHash,
81:             fieldHash
82:         )
83:         .GetHashCode();
84:     }
85: 
86:     /// <inheritdoc />
87:     public override bool Equals(object? obj)
88:         => obj is FieldIdentifier otherIdentifier
89:         && Equals(otherIdentifier);
90: 
91:     /// <inheritdoc />
92:     public bool Equals(FieldIdentifier otherIdentifier)
93:     {
94:         return ReferenceEquals(otherIdentifier.Model, Model) &&
95:             string.Equals(otherIdentifier.FieldName, FieldName, StringComparison.Ordinal);
96:     }
97: 
98:     private static void ParseAccessor<T>(Expression<Func<T>> accessor, out object model, out string fieldName)
99:     {
100:         var accessorBody = accessor.Body;
101: 
102:         // Unwrap casts to object
103:         if (accessorBody is UnaryExpression unaryExpression
104:             && unaryExpression.NodeType == ExpressionType.Convert
105:             && unaryExpression.Type == typeof(object))
106:         {
107:             accessorBody = unaryExpression.Operand;
108:         }
109: 
110:         switch (accessorBody)
111:         {
112:             case MemberExpression memberExpression:
113:                 // Identify the field name. We don't mind whether it's a property or field, or even something else.
114:                 fieldName = memberExpression.Member.Name;
115:                 // Get a reference to the model object
116:                 // i.e., given a value like "(something).MemberName", determine the runtime value of "(something)",
117:                 switch (memberExpression.Expression)
118:                 {
119:                     case ConstantExpression constant when constant.Value == null:
120:                         throw new ArgumentException("The provided expression must evaluate to a non-null value.");
121:                     case ConstantExpression constant when constant.Value != null:
122:                         model = constant.Value;
123:                         break;
124:                     case MemberExpression member when member.Expression is ConstantExpression:
125:                         model = GetModelFromMemberAccess(member);
126:                         break;
127:                     case not null:
128:                         // It would be great to cache this somehow, but it's unclear there's a reasonable way to do
129:                         // so, given that it embeds captured values such as "this". We could consider special-casing
130:                         // for "() => something.Member" and building a cache keyed by "something.GetType()" with values
131:                         // of type Func<object, object> so we can cheaply map from "something" to "something.Member".
132:                         var modelLambda = Expression.Lambda(typeof(Func<object?>), memberExpression.Expression);
133:                         var modelLambdaCompiled = (Func<object?>)modelLambda.Compile();
134:                         var result = modelLambdaCompiled() ??
135:                             throw new ArgumentException("The provided expression must evaluate to a non-null value.");
136: 
137:                         model = result;
138:                         break;
139:                     default:
140:                         throw new ArgumentException($"The provided expression contains a {accessorBody.GetType().Name} which is not supported. {nameof(FieldIdentifier)} only supports simple member accessors (fields, properties) of an object.");
141:                 }
142:                 break;
143:             case MethodCallExpression methodCallExpression when ExpressionFormatter.IsSingleArgumentIndexer(accessorBody):
144:                 fieldName = ExpressionFormatter.FormatIndexArgument(methodCallExpression.Arguments[0]);
145:                 model = GetModelFromIndexer(methodCallExpression.Object!);
146:                 break;
147:             case BinaryExpression binaryExpression when binaryExpression.NodeType == ExpressionType.ArrayIndex:
148:                 fieldName = ExpressionFormatter.FormatIndexArgument(binaryExpression.Right);
149:                 model = GetModelFromIndexer(binaryExpression.Left);
150:                 break;
151:             default:
152:                 throw new ArgumentException($"The provided expression contains a {accessorBody.GetType().Name} which is not supported. {nameof(FieldIdentifier)} only supports simple member accessors (fields, properties) of an object.");
153:         }
154:     }
155: 
156:     internal static object GetModelFromMemberAccess(
157:         MemberExpression member,
158:         ConcurrentDictionary<(Type ModelType, MemberInfo Member), Func<object, object>>? cache = null)
159:     {
160:         cache ??= _fieldAccessors;
161:         Func<object, object>? accessor = null;
162:         object? value = null;
163:         switch (member.Expression)
164:         {
165:             case ConstantExpression model:
166:                 value = model.Value ?? throw new ArgumentException("The provided expression must evaluate to a non-null value.");
167:                 accessor = cache.GetOrAdd((value.GetType(), member.Member), CreateAccessor);
168:                 break;
169:             default:
170:                 break;
171:         }
172: 
173:         if (accessor == null)
174:         {
175:             throw new InvalidOperationException($"Unable to compile expression: {member}");
176:         }
177: 
178:         if (value == null)
179:         {
180:             throw new ArgumentException("The provided expression must evaluate to a non-null value.");
181:         }
182: 
183:         var result = accessor(value);
184:         return result;
185: 
186:         [UnconditionalSuppressMessage(
187:             "Trimming",
188:             "IL2026:Members annotated with 'RequiresUnreferencedCodeAttribute' require dynamic access otherwise can break functionality when trimming application code",
189:             Justification = "Application code does not get trimmed. We expect the members in the expression to not be trimmed.")]
190:         static Func<object, object> CreateAccessor((Type model, MemberInfo member) arg)
191:         {
192:             var parameter = Expression.Parameter(typeof(object), "value");
193:             Expression expression = Expression.Convert(parameter, arg.model);
194: 
195:             expression = Expression.MakeMemberAccess(expression, arg.member);
196:             expression = Expression.Convert(expression, typeof(object));
197:             var lambda = Expression.Lambda<Func<object, object>>(expression, parameter);
198: 
199:             var func = lambda.Compile();
200:             return func;
201:         }
202:     }
203: 
204:     private static object GetModelFromIndexer(Expression methodCallExpression)
205:     {
206:         object model;
207:         var methodCallObjectLambda = Expression.Lambda(typeof(Func<object?>), methodCallExpression!);
208:         var methodCallObjectLambdaCompiled = (Func<object?>)methodCallObjectLambda.Compile();
209:         var result = methodCallObjectLambdaCompiled();
210:         if (result is null)
211:         {
212:             throw new ArgumentException("The provided expression must evaluate to a non-null value.");
213:         }
214:         model = result;
215:         return model;
216:     }
217: 
218:     private static void ClearCache()
219:     {
220:         _fieldAccessors.Clear();
221:     }
222: }
