11: /// <summary>
12: /// Displays the specified content inside the specified layout and any further
13: /// nested layouts.
14: /// </summary>
15: public class LayoutView : IComponent
16: {
17:     private static readonly RenderFragment EmptyRenderFragment = builder => { };
18: 
19:     private RenderHandle _renderHandle;
20: 
21:     /// <summary>
22:     /// Gets or sets the content to display.
23:     /// </summary>
24:     [Parameter]
25:     public RenderFragment ChildContent { get; set; } = default!;
26: 
27:     /// <summary>
28:     /// Gets or sets the type of the layout in which to display the content.
29:     /// The type must implement <see cref="IComponent"/> and accept a parameter named <see cref="LayoutComponentBase.Body"/>.
30:     /// </summary>
31:     [Parameter]
32:     [DynamicallyAccessedMembers(Component)]
33:     public Type Layout { get; set; } = default!;
34: 
35:     /// <inheritdoc />
36:     public void Attach(RenderHandle renderHandle)
37:     {
38:         _renderHandle = renderHandle;
39:     }
40: 
41:     /// <inheritdoc />
42:     public Task SetParametersAsync(ParameterView parameters)
43:     {
44:         parameters.SetParameterProperties(this);
45:         Render();
46:         return Task.CompletedTask;
47:     }
48: 
49:     [UnconditionalSuppressMessage("Trimming", "IL2072", Justification = "Layout components are preserved because the LayoutAttribute constructor parameter is correctly annotated.")]
50:     private void Render()
51:     {
52:         // In the middle goes the supplied content
53:         var fragment = ChildContent ?? EmptyRenderFragment;
54: 
55:         // Then repeatedly wrap that in each layer of nested layout until we get
56:         // to a layout that has no parent
57:         var layoutType = Layout;
58:         while (layoutType != null)
59:         {
60:             fragment = WrapInLayout(layoutType, fragment);
61:             layoutType = GetParentLayoutType(layoutType);
62:         }
63: 
64:         _renderHandle.Render(fragment);
65:     }
66: 
67:     private static RenderFragment WrapInLayout([DynamicallyAccessedMembers(Component)] Type layoutType, RenderFragment bodyParam)
68:     {
69:         void Render(RenderTreeBuilder builder)
70:         {
71:             builder.OpenComponent(0, layoutType);
72:             builder.AddComponentParameter(1, LayoutComponentBase.BodyPropertyName, bodyParam);
73:             builder.CloseComponent();
74:         };
75: 
76:         return Render;
77:     }
78: 
79:     private static Type? GetParentLayoutType(Type type)
80:         => type.GetCustomAttribute<LayoutAttribute>()?.LayoutType;
81: }
